public extension View {
    /// Position a view on a sphere centered on the device and rotated using real world coordinates. This view will rotate to compensate for device rotation and appear to be seen either through a window or as a kind of reflection.
    ///
    /// - Requires: Use the `.motionManager` view modifier only once in your app somewhere above this view in the heirarchy.
    ///
    /// - Parameters:
    ///   - type: Device rotation effect.
    ///   - distance: Distance the view is positioned from the device in points.
    ///   - perspective: Amount of perspective used in the view projection. (default of zero creates an orthographic projection where the view will not decrease in size based on distance)
    ///   - offsetRotation: Quaternion that represents the view's position in the real world. (zero positions the view on the ground)
    ///   - isShowingInFourDirections: If active the view will be rotated around the Z axis at 90 degree intervals to always face the direction the device is pointing.
    /// - Returns: The view is positioned centered on the device and rotated using real world coordinates. It will rotate to compensate for device rotation and appear to be seen either through a window or as a kind of reflection.
    func deviceRotationEffect(
        _ type: DeviceRotationEffectType,
        distance: CGFloat? = nil,
        perspective: CGFloat? = nil,
        offsetRotation: Quat? = nil,
        isShowingInFourDirections: Bool? = nil
    ) -> some View {
        self.modifier(
            DeviceRotationEffectViewModifier(
                type: type,
                distance: distance,
                perspective: perspective,
                offsetRotation: offsetRotation,
                isShowingInFourDirections: isShowingInFourDirections
            )
        )
    }
    /// Position a view on a sphere centered on the device and rotated using real world coordinates. This view will rotate to compensate for device rotation and appear to be seen either through a window or as a kind of reflection.
    ///
    /// - Requires: Use the `.motionManager` view modifier only once in your app somewhere above this view in the heirarchy.
    /// 
    /// - Parameters:
    ///   - type: Device rotation effect.
    ///   - distance: Distance the view is positioned from the device in points.
    ///   - perspective: Amount of perspective used in the view projection. (default of zero creates an orthographic projection where the view will not decrease in size based on distance)
    ///   - pitch: Pitch rotation of the view (zero = on the ground, 90 degrees = in front, 180 degrees = on the ceiling)
    ///   - yaw: Yaw rotation of the view (zero = in front, 90 degrees = left, -90 degrees = right, 180 degrees = behind)
    ///   - localRoll: Local roll rotation of the view.
    ///   - isShowingInFourDirections: If active the view will be rotated around the Z axis at 90 degree intervals to always face the direction the device is pointing.
    /// - Returns: The view is positioned centered on the device and rotated using real world coordinates. It will rotate to compensate for device rotation and appear to be seen either through a window or as a kind of reflection.
    func deviceRotationEffect(
        _ type: DeviceRotationEffectType,
        distance: CGFloat? = nil,
        perspective: CGFloat? = nil,
        pitch: Angle? = nil,
        yaw: Angle? = nil,
        localRoll: Angle? = nil,
        isShowingInFourDirections: Bool? = nil
    ) -> some View {
        deviceRotationEffect(
            type,
            distance: distance,
            perspective: perspective,
            offsetRotation: Quat(pitch: pitch,
            yaw: yaw,
            localRoll: localRoll),
            isShowingInFourDirections: isShowingInFourDirections
        )
    }
}

public struct LookingGlass<Content: View>: View {
    @EnvironmentObject var motionManager: MotionManager
    let type: DeviceRotationEffectType
    let distance: CGFloat?
    let perspective: CGFloat?
    let offsetRotation: Quat?
    let isShowingInFourDirections: Bool?
    let content: Content
    /// A view that rotates another view so it appears locked to real-world orientations. Useful if you want a view that is only visible when the phone is pointed in a specific direction.
    ///
    /// This view will take all proposed space similar to `GeometryReader`. The content view will always be aligned to the centre of the device and the centre of the screen regardless of where the view is on the screen or inside a scrollview.
    ///
    /// If motion updates are off the content will not be shown.
    ///
    /// - Requires: ``motionManager(updateInterval:disabled:)`` must be added only once in your app somewhere above this view in the heirarchy.
    /// - Parameters:
    ///   - type: Device rotation effect.
    ///   - distance: Distance the view is positioned from the device in points.
    ///   - perspective: Amount of perspective used in the view projection. (default of zero creates an orthographic projection where the view will not decrease in size based on distance)
    ///   - offsetRotation: Quaternion that represents the view's position in the real world. (zero positions the view on the ground.)
    ///   - isShowingInFourDirections: If active the view will be rotated around the Z axis at 90 degree intervals to always face the direction the device is pointing.
    ///   - content: View to be shown.
    public init(
        _ type: DeviceRotationEffectType,
        distance: CGFloat? = nil,
        perspective: CGFloat? = nil,
        offsetRotation: Quat? = nil,
        isShowingInFourDirections: Bool? = nil,
        content: () -> Content
    ) {
        self.type = type
        self.distance = distance
        self.perspective = perspective
        self.offsetRotation = offsetRotation
        self.isShowingInFourDirections = isShowingInFourDirections
        self.content = content()
    }
    /// A view that rotates another view so it appears locked to real-world orientations. Useful if you want a view that is only visible when the phone is pointed in a specific direction.
    ///
    /// This view will take all proposed space similar to `GeometryReader`. The content view will always be aligned to the centre of the device and the centre of the screen regardless of where the view is on the screen or inside a scrollview.
    ///
    /// If motion updates are off the content will not be shown.
    ///
    /// - Requires: ``motionManager(updateInterval:disabled:)`` must be added only once in your app somewhere above this view in the heirarchy.
    ///
    /// - Parameters:
    ///   - type: Device rotation effect.
    ///   - distance: Distance the view is positioned from the device in points.
    ///   - perspective: Amount of perspective used in the view projection. (default of zero creates an orthographic projection where the view will not decrease in size based on distance)
    ///   - pitch: The pitch rotation applied to the view relative to the real world.
    ///   - yaw: The yaw rotation applied to the view relative to the real world.
    ///   - localRoll: The local roll applied to the view.
    ///   - isShowingInFourDirections: If active the view will be rotated around the Z axis at 90 degree intervals to always face the direction the device is pointing.
    ///   - content: View to be shown.
    public init(
        _ type: DeviceRotationEffectType,
        distance: CGFloat,
        perspective: CGFloat? = nil,
        pitch: Angle? = nil,
        yaw: Angle? = nil,
        localRoll: Angle? = nil,
        isShowingInFourDirections: Bool? = nil,
        content: () -> Content
    ) {
        self.init(
            type,
            distance: distance,
            perspective: perspective,
            offsetRotation: Quat(pitch: pitch, yaw: yaw, localRoll: localRoll),
            isShowingInFourDirections: isShowingInFourDirections,
            content: content
        )
    }
    public var body: some View {
        if motionManager.isDetectingMotion {
            GeometryReader { proxy in
                content
                    .deviceRotationEffect(type, distance: distance, perspective: perspective, offsetRotation: offsetRotation, isShowingInFourDirections: isShowingInFourDirections)
                    .frame(width: motionManager.interfaceSize.width, height: motionManager.interfaceSize.height)
                    .offset(x: (proxy.size.width / 2) - proxy.frame(in: .global).midX, y: (proxy.size.height / 2) - proxy.frame(in: .global).midY)
            }
        } else {
            Color.clear
        }
    }
}

public class MotionManager: ObservableObject {
    /// Only one shared MotionManager should be used in an app
    static let shared = MotionManager()
    private init() { }
    static let motionQueue = OperationQueue()
    static let screenSize = UIScreen.main.bounds.size
    static let maxScreenDimension = max(MotionManager.screenSize.height, MotionManager.screenSize.width)
    private let cmManager = CMMotionManager()
    @Published public private(set) var updateInterval: TimeInterval = 0
    @Published public private(set) var disabled: Bool = false
    @Published public private(set) var deviceOrientation: UIDeviceOrientation = .unknown
    /// Rotation of device relative to zero position. Value is updated with SwiftUI animation to smooth between update intervals.
    @Published public private(set) var animatedQuaternion: Quat = .identity
    /// Rotation of device relative to zero position. Value is updated based on update intervals without animation or smoothing.
    @Published public private(set) var quaternion: Quat = .identity
    /// Rotation from zero to initial position of device when motion updates started.
    ///
    /// This value is reset whenever motion manager is re-enabled.
    @Published public private(set) var initialDeviceRotation: Quat? = nil
    /// Rotation from initial device rotation to current.
    public var deltaRotation: Quat {
        guard let initialDeviceRotation = initialDeviceRotation else {
            return .identity
        }
        return (animatedQuaternion * initialDeviceRotation.inverse)
    }
    public var interfaceRotation: Quat {
        switch deviceOrientation {
        case .landscapeLeft:
            return Quat(angle: .radians(-.pi / 2), axis: .zAxis)
        case .landscapeRight:
            return Quat(angle: .radians(.pi / 2), axis: .zAxis)
        case .portraitUpsideDown:
            return Quat(angle: .radians(.pi), axis: .zAxis)
        default:
            return .identity
        }
    }
    /// True if update interval greater than zero and not disabled.
    public var isDetectingMotion: Bool {
        updateInterval > 0 && !disabled
    }
    /// The device screen size taking into account device orientation.
    var interfaceSize: CGSize {
        switch deviceOrientation {
        case .landscapeRight, .landscapeLeft:
            return CGSize(width: Self.screenSize.height, height: Self.screenSize.width)
        default:
            return Self.screenSize
        }
    }
    /// Changes the device orientation property if the new orientation is supported.
    public func changeDeviceOrientation() {
        let newOrientation = UIDevice.current.orientation
        guard deviceOrientation != newOrientation else {
            return
        }
        if InfoDictionary.supportedOrientations.contains(newOrientation) {
            initialDeviceRotation = nil
            self.deviceOrientation = newOrientation
            restartMotionUpdatesIfNeeded()
        }
    }
    /// Sets the update interval to the value specified
    /// - Parameter newUpdateInterval: New update interval
    public func setUpdateInterval(_ newUpdateInterval: TimeInterval) {
        if updateInterval != newUpdateInterval {
            updateInterval = newUpdateInterval
            restartMotionUpdatesIfNeeded()
        }
    }
    /// Sets the disabled property to the value specified
    /// - Parameter newDisabled: New disabled value.
    public func setDisabled(_ newDisabled: Bool) {
        if disabled != newDisabled {
            disabled = newDisabled
            restartMotionUpdatesIfNeeded()
        }
    }
    /// Method to update several properties at once.
    /// - Parameters:
    ///   - updateInterval: Time between motion updates.
    ///   - disabled: If true, motion updates are disabled.
    ///   - setDeviceOrientation: If true, device orientation is updated.
    public func startMotionUpdates(updateInterval: TimeInterval? = nil, disabled: Bool? = nil, setDeviceOrientation: Bool = false) {
        if let disabled, self.disabled != disabled {
            self.disabled = disabled
        }
        if let updateInterval, self.updateInterval != updateInterval {
            self.updateInterval = updateInterval
        }
        if setDeviceOrientation {
            let newOrientation = UIDevice.current.orientation
            if deviceOrientation != newOrientation,
               InfoDictionary.supportedOrientations.contains(newOrientation) {
                initialDeviceRotation = nil
                deviceOrientation = newOrientation
            }
        }
        restartMotionUpdatesIfNeeded()
    }
    /// Restarts motion updates
    public func restart() {
        restartMotionUpdatesIfNeeded()
    }
    /// Stops motion updates. This must be run before deinit. Currently this is done with `.onDisappear()` in ``MotionManagerViewModifier``
    public func stopMotionUpdates() {
        if cmManager.isDeviceMotionActive {
            cmManager.stopDeviceMotionUpdates()
        }
    }
    /// Toggles motion updates off if on or on if off (and not disabled and update interval greater than zero).
    private func restartMotionUpdatesIfNeeded() {
        stopMotionUpdates()
        guard updateInterval > 0 && !disabled else { return }
        cmManager.deviceMotionUpdateInterval = updateInterval
        cmManager.startDeviceMotionUpdates(to: .main) { motionData, error in
            if let motionData = motionData {
                let quaternion = Quat(motionData.attitude.quaternion)
                if self.initialDeviceRotation == nil {
                    self.initialDeviceRotation = quaternion
                }
                self.quaternion = quaternion
                withAnimation(Animation.linear(duration: self.updateInterval)) {
                    self.animatedQuaternion = quaternion
                }
            } else if let error = error {
                print(error.localizedDescription)
            } else {
                print("Error - Unknown motion update error")
            }
        }
    }
}

struct MotionManagerViewModifier: ViewModifier {
    @ObservedObject var motionManager = MotionManager.shared
    let updateInterval: TimeInterval
    let disabled: Bool
    func body(content: Content) -> some View {
        content
            .environmentObject(motionManager)
            .onReceive(NotificationCenter.default.publisher(for: UIDevice.orientationDidChangeNotification)) { _ in
                motionManager.changeDeviceOrientation()
            }
            .onReceive(NotificationCenter.default.publisher(for: UIApplication.willEnterForegroundNotification)) { _ in
                motionManager.startMotionUpdates(updateInterval: updateInterval, disabled: disabled, setDeviceOrientation: true)
            }
            .onReceive(NotificationCenter.default.publisher(for: UIApplication.didEnterBackgroundNotification)) { _ in
                motionManager.stopMotionUpdates()
            }
            .onAppear {
                motionManager.startMotionUpdates(updateInterval: updateInterval, disabled: disabled, setDeviceOrientation: true)
            }
            .onDisappear {
                motionManager.stopMotionUpdates()
            }
            .onChange(of: updateInterval) {
                motionManager.setUpdateInterval($0)
            }
            .onChange(of: disabled) {
                motionManager.setDisabled($0)
            }
    }
}

struct ParallaxViewModifier: ViewModifier {
    @EnvironmentObject var motionManager: MotionManager
    let multiplier: CGFloat
    let maxOffset: CGFloat?
    var deltaScreenRotation: Quat {
        /// all rotations are provided in the device reference frame
        /// Rotations occur in reverse order
        /// 1. Reference frame is changed from screen to device (x and z flip)
        /// 2. result is rotated by the delta between the initial rotation and the current rotation
        /// 3. result is rotated by the inverse of the interface rotation to counteract any interface orientation changes
        (motionManager.interfaceRotation.inverse * motionManager.deltaRotation)
            .deviceToScreenReferenceFrame
    }
    var parallaxOffset: CGSize {
        guard motionManager.isDetectingMotion else { return .zero }
        let maxOffset = maxOffset ?? .infinity
        let x = -min(max(-maxOffset, deltaScreenRotation.yaw.radians * multiplier), maxOffset)
        let y = min(max(-maxOffset, deltaScreenRotation.pitch.radians * multiplier), maxOffset)
        return CGSize(width: x, height: y)
    }
    func body(content: Content) -> some View {
        content
            .offset(parallaxOffset)
    }
}

public extension Quat {
    /// Creates a quaternion from components.
    init(_ x: Double, _ y: Double, _ z: Double, _ w: Double) {
        simd = .init(ix: x, iy: y, iz: z, r: w)
    }
    var x: Double {
        get { simd.imag.x }
        set { simd.imag.x = newValue }
    }
    var y: Double {
        get { simd.imag.y }
        set { simd.imag.y = newValue }
    }
    var z: Double {
        get { simd.imag.z }
        set { simd.imag.z = newValue }
    }
    var w: Double {
        get { simd.real }
        set { simd.real = newValue }
    }
    /// The identity quaternion.
    static let identity = Self(0, 0, 0, 1)
    /// The axis vector when this quaternion is represented as an axis and a rotation.
    var axis: Vec3 {
        .init(simd.axis)
    }
    /// The angle of rotation when this quaternion is represented as an axis and a rotation.
    var angle: Angle {
        .radians(simd.angle)
    }
    @available(*, deprecated, renamed: "angle")
    var rotationAngle: Angle {
        angle
    }
    /// The complex conjugate of this quaternion.
    var conjugate: Self {
        .init(simd.conjugate)
    }
    /// A normalized version of this quaternion.
    var normalized: Self {
        .init(simd.normalized)
    }
    /// The inverse of this quaternion.
    var inverse: Self {
        .init(simd.inverse)
    }
    /// Creates a quaternion from a rotation angle and axis vector.
    /// - Parameters:
    ///   - angle: Angle of rotation.
    ///   - axis: Axis for the rotation.
    init(angle: Angle, axis: Vec3) {
        simd = simd_quaternion(angle.radians, axis)
    }
    /// Multiplication for two quaternions (order matters)
    static func * (lhs: Self, rhs: Self) -> Self {
        .init(simd_mul(lhs.simd, rhs.simd))
    }
    /// A quaternion created from pitch, yaw, and local roll angles.
    /// - Parameters:
    ///   - pitch: rotation around X axis. Default is zero.
    ///   - yaw: rotation around Z axis. Default is zero.
    ///   - localRoll: rotation around local Z axis. Default is zero.
    init(pitch: Angle? = nil, yaw: Angle? = nil, localRoll: Angle? = nil) {
        let pitch = Self(angle: pitch ?? .zero, axis: .xAxis)
        let yaw = Self(angle: yaw ?? .zero, axis: .zAxis)
        let localRoll = Self(angle: localRoll ?? .zero, axis: .zAxis)
        self = yaw * pitch * localRoll
    }
    /// The yaw angle (rotation around the Y axis) between -180 to 180 degrees.
    @inlinable var yaw: Angle {
        /// https://github.com/OGRECave/ogre/blob/master/OgreMain/src/OgreQuaternion.cpp#L508
        .radians(asin(-2 * (x * z - w * y)))
    }
    /// The pitch angle (rotation around the X zxis) between -180 to 180 degrees.
    @inlinable var pitch: Angle {
        /// https://github.com/OGRECave/ogre/blob/master/OgreMain/src/OgreQuaternion.cpp#L484
        .radians(atan2(2.0 * (y * z + w * x), w * w - x * x - y * y + z * z))
    }
    /// The roll angle (rotation around the Z axis) between -180 to 180 degrees.
    @inlinable var roll: Angle {
        /// https://github.com/OGRECave/ogre/blob/master/OgreMain/src/OgreQuaternion.cpp#L459
        .radians(atan2(2.0 * (x * y + w * z), w * w + x * x - y * y - z * z))
    }
    /// Returns the angle between two quaternions
    /// - Parameter q2: Second quaternion.
    /// - Returns: Angle in radians between two quaternions.
    func rotationAngle(to q2: Self) -> Angle {
        (conjugate * q2).angle
    }
    /// Transformation from device reference frame to screen reference frame.
    ///
    /// Device reference frame:
    /// With device flat and top facing forward
    /// +X is left
    /// +Y is forward
    /// +Z is down
    /// rotations follow right hand rule
    var deviceToScreenReferenceFrame: Self {
        Self(-x, y, -z, w)
    }
    /// Transformation from screen reference frame to device reference frame.
    ///
    /// Screen reference frame
    /// With device flat and top facing forward
    /// +X is right
    /// +Y is forward
    /// +Z is up
    /// rotations follow right hand rule
    var screenToDeviceReferenceFrame: Self {
        deviceToScreenReferenceFrame
    }
    /// Returns a vector rotated by this quaternion.
    ///
    /// - Parameters:
    ///   - vector: Vector to be rotated.
    /// - Returns: The rotated vector.
    func rotating(_ vector: Vec3) -> Vec3 {
        simd_act(simd.normalized, vector)
    }
}

public struct QuaternionDataView: View {
    let quat: Quat?
    public init(_ quat: Quat?) {
        self.quat = quat
    }
    @ViewBuilder
    public var body: some View {
        if let quat {
            Section(header: Text("Axis Vector and angle")) {
                data("Axis Vector x", quat.axis.x)
                data("Axis Vector y", quat.axis.y)
                data("Axis Vector z", quat.axis.z)
                data("Angle (degrees)", quat.angle.degrees)
            }
            Section(header: Text("Rotation components")) {
                data("Pitch (degrees)", quat.pitch.degrees)
                data("Yaw (degrees)", quat.yaw.degrees)
                data("Roll (degrees)", quat.roll.degrees)
            }
        } else {
            Text("Quat: Nil")
        }
    }
    func data(_ label: String, _ value: Double) -> some View {
        Text("\(label): \(value)")
            .accessibilityLabel(label)
            .accessibilityValue(String(value))
            .accessibilityAddTraits(.updatesFrequently)
    }
}
